settings.markdownCss:
.card, .no-data-card {
    padding: 0px;
    height: 100%;
}
.card-title {
    position: sticky;
    top: 0;
    z-index: 2;
    font-size: 16px;
    letter-spacing: 0.25px;
    padding: 16px;
}
.attribute_container {
    display: flex;
    align-items: center;
    gap: 20px;
    padding: 16px;
    border-bottom: 1px solid #0000000d;
}
.icon {
    z-index: 1;
}
.icon_wrapper {
    display: flex;
    position: relative;
    align-items: center;
    padding: 8px;
    border: 1px solid var(--tb-primary-100, #305680);
    border-radius: 4px;
}
.icon_wrapper:before {
    content: '';
    z-index: 0;
    position: absolute;
    opacity: 0.1;
    background-color: var(--tb-primary-200, #305680);
    width: 100%;
    height: 100%;
    left: 0;
    top: 0;
}
.attribute, .attribute_label {
    font-size: 14px;
    line-height: 20px;
}
.attribute_label {
    color: #00000061;
}
.no-data-card {
    display: flex;
    flex-direction: column;
}
.no-data-block {
    display: flex;
    flex-direction: column;
    justify-content: center;
    height: 100%;
    max-width: 345px;
    padding: 0 15px;
    margin: 0 auto;
    text-align: center;
}
.no-data-content {
    transform: translateY(-30%);
}
.no-data-block p {
    font-weight: 500;
}
.no-data-title {
    color: rgba(0, 0, 0, 0.54);
}
.no-data-subtitle {
    font-size: 13px;
    color: rgba(0, 0, 0, 0.38);
}

labelColor.colorFunction:
var temperature = value;
if (typeof temperature !== undefined) {
  var percent = (temperature + 60)/120 * 100;
  return tinycolor.mix('blue', 'red', percent).toHexString();
}
return 'blue';

